"use client";

import { motion } from "framer-motion";
import { ArrowRight, MoveDown, LayoutGrid, MonitorSmartphone, Rocket, Zap } from "lucide-react";
import SplineBackground from "@/components/SplineBackground";
import CanvasSequence from "@/components/CanvasSequence";

export default function Home() {

  const fadeInUp: any = {
    hidden: { opacity: 0, y: 50 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.8, ease: "easeOut" } }
  };

  const staggerContainer: any = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.2 }
    }
  };

  return (
    <main style={{ position: "relative" }}>
      {/* Background Managers */}
      <div style={{ position: "fixed", top: 0, left: 0, width: "100%", height: "100%", zIndex: -1 }}>
        <CanvasSequence />
      </div>

      <div style={{ position: "fixed", top: 0, left: 0, width: "100%", height: "100%", zIndex: -2 }}>
        <SplineBackground />
      </div>

      {/* Hero Section (0 - 15%) */}
      <section style={{ 
        height: "120vh", 
        display: "flex", 
        flexDirection: "column", 
        justifyContent: "center", 
        padding: "0 5%",
        position: "relative"
      }}>
        <motion.div 
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1, delay: 0.5 }}
          style={{ maxWidth: "800px", zIndex: 10 }}
        >
          <motion.h1 
            style={{ 
              fontSize: "clamp(3rem, 6vw, 5.5rem)", 
              fontWeight: 800,
              lineHeight: 1.1,
              marginBottom: "1.5rem"
            }}
          >
            Build <span className="text-gradient">Premium Websites</span> That Convert & Scale
          </motion.h1>
          <motion.p 
            style={{
              fontSize: "clamp(1.1rem, 2vw, 1.3rem)",
              color: "var(--text-muted)",
              marginBottom: "3rem",
              maxWidth: "600px",
              lineHeight: 1.6
            }}
          >
            We craft modern, high-performance digital experiences. Transform your brand with award-winning design and cutting-edge technology.
          </motion.p>
          <motion.div style={{ display: "flex", gap: "1rem", flexWrap: "wrap" }}>
            <button className="primary-btn flex-center" style={{ gap: "0.5rem" }}>
              Get Started <ArrowRight size={18} />
            </button>
            <button className="secondary-btn">
              View Work
            </button>
          </motion.div>
        </motion.div>

        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 2, duration: 1 }}
          style={{ 
            position: "absolute", 
            bottom: "15%", 
            left: "5%",
            display: "flex",
            alignItems: "center",
            gap: "1rem",
            color: "var(--text-muted)"
          }}
        >
          <span style={{ fontSize: "0.9rem", letterSpacing: "2px", textTransform: "uppercase" }}>Scroll</span>
          <motion.div
            animate={{ y: [0, 10, 0] }}
            transition={{ repeat: Infinity, duration: 1.5 }}
          >
            <MoveDown size={20} />
          </motion.div>
        </motion.div>
      </section>

      {/* Brand Experience Section (15 - 40%) */}
      <section 
        id="process"
        style={{ 
          height: "150vh", 
          display: "flex", 
          alignItems: "center", 
          padding: "0 5%" 
        }}
      >
        <motion.div 
          variants={fadeInUp}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: false, margin: "-20%" }}
          style={{ maxWidth: "700px" }}
        >
          <h2 style={{ fontSize: "clamp(2.5rem, 5vw, 4.5rem)", fontWeight: 700, marginBottom: "1.5rem", lineHeight: 1.1 }}>
            Next-Gen <br /> <span className="text-gradient">Web Experiences</span>
          </h2>
          <p style={{ fontSize: "1.2rem", color: "var(--text-muted)", lineHeight: 1.8 }}>
            We don't just build websites; we design immersive digital products that feel alive.
            By blending aesthetic brilliance with seamless functionality, we ensure every interaction leaves a lasting impression.
          </p>
        </motion.div>
      </section>

      {/* Services Section (40 - 65%) */}
      <section 
        id="services"
        style={{ 
          height: "180vh", 
          padding: "10rem 5%",
          display: "flex",
          flexDirection: "column",
          justifyContent: "center"
        }}
      >
        <motion.h2 
          variants={fadeInUp}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: false }}
          style={{ fontSize: "clamp(2rem, 4vw, 3.5rem)", textAlign: "center", marginBottom: "5rem" }}
        >
          Our <span style={{ color: "var(--primary)" }}>Expertise</span>
        </motion.h2>

        <motion.div 
          variants={staggerContainer}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: false, margin: "-10%" }}
          style={{ 
            display: "grid", 
            gridTemplateColumns: "repeat(auto-fit, minmax(300px, 1fr))", 
            gap: "2rem",
            maxWidth: "1200px",
            margin: "0 auto"
          }}
        >
          {[
            { title: "Website Development", icon: <MonitorSmartphone size={32} />, desc: "High-performance websites built with Next.js and modern stacks." },
            { title: "3D Web Design", icon: <LayoutGrid size={32} />, desc: "Immersive Spline scenes and WebGL experiences that captivate." },
            { title: "UI/UX Design", icon: <Zap size={32} />, desc: "Intuitive, premium user interfaces designed for conversion." },
            { title: "Optimization", icon: <Rocket size={32} />, desc: "Lightning fast digital products optimized for global scale." }
          ].map((service, i) => (
            <motion.div key={i} variants={fadeInUp} className="glass-card" style={{ display: "flex", flexDirection: "column", gap: "1.5rem" }}>
              <div style={{ color: "var(--primary)" }}>{service.icon}</div>
              <h3 style={{ fontSize: "1.5rem" }}>{service.title}</h3>
              <p style={{ color: "var(--text-muted)", lineHeight: 1.6 }}>{service.desc}</p>
            </motion.div>
          ))}
        </motion.div>
      </section>

      {/* Portfolio Section (65 - 85%) */}
      <section 
        id="work"
        style={{ 
          height: "160vh", 
          padding: "5rem 5%",
          display: "flex",
          flexDirection: "column",
          justifyContent: "center"
        }}
      >
        <motion.div 
          variants={fadeInUp}
          initial="hidden"
          whileInView="visible"
          style={{ maxWidth: "600px", marginBottom: "4rem" }}
        >
          <h2 style={{ fontSize: "clamp(2.5rem, 5vw, 4.5rem)", fontWeight: 700, marginBottom: "1rem" }}>
            Featured <span style={{ color: "var(--secondary)" }}>Work</span>
          </h2>
          <p style={{ color: "var(--text-muted)", fontSize: "1.1rem" }}>Where visionary design meets flawless execution.</p>
        </motion.div>

        <div style={{ display: "flex", flexDirection: "column", gap: "6rem" }}>
          {[
            { name: "Aura Fintech", cat: "Fintech App UI/UX", align: "flex-start" },
            { name: "Nexus 3D", cat: "Immersive E-commerce", align: "flex-end" }
          ].map((project, i) => (
            <motion.div 
              key={i}
              initial={{ opacity: 0, x: project.align === "flex-start" ? -50 : 50 }}
              whileInView={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8 }}
              viewport={{ once: false, margin: "-20%" }}
              style={{ alignSelf: project.align, width: "100%", maxWidth: "800px" }}
            >
              <div style={{ 
                width: "100%", 
                aspectRatio: "16/9", 
                backgroundColor: "rgba(255,255,255,0.02)",
                borderRadius: "20px",
                border: "1px solid rgba(255,255,255,0.05)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                color: "rgba(255,255,255,0.2)",
                fontSize: "1.2rem",
                marginBottom: "2rem",
                overflow: "hidden",
                position: "relative"
              }}>
                <div style={{
                  position: "absolute",
                  inset: 0,
                  background: `linear-gradient(45deg, transparent, rgba(108, 99, 255, 0.${1 + i}), transparent)`
                }}></div>
                [ Project Visual Preview ]
              </div>
              <h3 style={{ fontSize: "2rem", marginBottom: "0.5rem" }}>{project.name}</h3>
              <p style={{ color: "var(--secondary)", fontWeight: 500 }}>{project.cat}</p>
            </motion.div>
          ))}
        </div>
      </section>

      {/* Final CTA (85 - 100%) */}
      <section style={{ 
        height: "100vh", 
        display: "flex", 
        alignItems: "center", 
        justifyContent: "center",
        textAlign: "center",
        padding: "0 5%",
        background: "linear-gradient(to top, rgba(10,10,15,1), transparent)"
      }}>
        <motion.div 
          variants={fadeInUp}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: false }}
          style={{ maxWidth: "800px", padding: "4rem", borderRadius: "30px", background: "rgba(255,255,255,0.02)", backdropFilter: "blur(20px)", border: "1px solid rgba(255,255,255,0.05)" }}
        >
          <h2 className="glow-text" style={{ fontSize: "clamp(2.5rem, 5vw, 4.5rem)", fontWeight: 800, marginBottom: "1.5rem" }}>
            Ready to Build Something <span style={{ color: "var(--primary)" }}>Powerful?</span>
          </h2>
          <p style={{ color: "var(--text-muted)", fontSize: "1.2rem", marginBottom: "3rem", maxWidth: "500px", margin: "0 auto 3rem" }}>
            Let's turn your vision into a digital masterpiece. Partner with NTI to lead your industry.
          </p>
          <div style={{ display: "flex", gap: "1.5rem", justifyContent: "center", flexWrap: "wrap" }}>
            <button className="primary-btn flex-center" style={{ gap: "0.5rem", padding: "1rem 2.5rem", fontSize: "1.1rem" }}>
              Book Call
            </button>
            <button className="secondary-btn flex-center" style={{ gap: "0.5rem", padding: "1rem 2.5rem", fontSize: "1.1rem", borderColor: "#25D366", color: "#25D366" }}>
              WhatsApp Us
            </button>
          </div>
        </motion.div>
      </section>

    </main>
  );
}

