"use client";

import { useEffect, useRef, useState } from "react";
import { motion, useScroll, useTransform, useMotionValueEvent } from "framer-motion";

const TOTAL_FRAMES = 680;

const getFramePath = (index: number) => {
  if (index <= 200) {
    return `/images/1 (${index}).jpg`;
  } else if (index <= 440) {
    return `/images/2 (${index - 200}).jpg`;
  } else {
    return `/images/3 (${Math.min(240, index - 440)}).jpg`;
  }
};

export default function CanvasSequence() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const { scrollYProgress } = useScroll();
  const [imagesMap, setImagesMap] = useState<Map<number, HTMLImageElement>>(new Map());

  // Map 0% to 100% scroll to frame 1 to 680, so every scroll step is a new frame immediately
  const frameIndex = useTransform(scrollYProgress, [0, 1], [1, TOTAL_FRAMES]);

  // Preloader
  useEffect(() => {
    // Preload first few frames immediately
    for (let i = 1; i <= 30; i++) {
      const img = new Image();
      img.src = getFramePath(i);
      imagesMap.set(i, img);
    }
    setImagesMap(new Map(imagesMap));
  }, []);

  const drawFrame = (index: number) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let img = imagesMap.get(index);

    if (!img) {
      img = new Image();
      img.src = getFramePath(index);

      // Once loaded, if this is still the current frame, draw it
      img.onload = () => {
        imagesMap.set(index, img!);
        setImagesMap(new Map(imagesMap));
        if (Math.round(frameIndex.get()) === index) {
          drawCenteredImage(ctx, canvas, img!);
        }
      };
    } else if (img.complete) {
      drawCenteredImage(ctx, canvas, img);
    }

    // Preload next 10 frames
    for (let i = index + 1; i <= Math.min(TOTAL_FRAMES, index + 10); i++) {
        if (!imagesMap.has(i)) {
            const nextImg = new Image();
            nextImg.src = getFramePath(i);
            imagesMap.set(i, nextImg);
        }
    }
  };

  const drawCenteredImage = (ctx: CanvasRenderingContext2D, canvas: HTMLCanvasElement, img: HTMLImageElement) => {
    // Fill background
    ctx.fillStyle = "#0A0A0F";
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const canvasRatio = canvas.width / canvas.height;
    const imgRatio = img.width / img.height;

    let drawWidth, drawHeight, offsetX = 0, offsetY = 0;

    if (canvasRatio > imgRatio) {
      drawWidth = canvas.width;
      drawHeight = canvas.width / imgRatio;
      offsetY = (canvas.height - drawHeight) / 2;
    } else {
      drawHeight = canvas.height;
      drawWidth = canvas.height * imgRatio;
      offsetX = (canvas.width - drawWidth) / 2;
    }

    ctx.drawImage(img, offsetX, offsetY, drawWidth, drawHeight);
  };

  useMotionValueEvent(frameIndex, "change", (latest) => {
    const frame = Math.round(latest);
    if (frame >= 1 && frame <= TOTAL_FRAMES) {
      drawFrame(frame);
    }
  });

  useEffect(() => {
    const handleResize = () => {
      const canvas = canvasRef.current;
      if (canvas) {
        // High DPI canvas
        const dpr = window.devicePixelRatio || 1;
        canvas.width = window.innerWidth * dpr;
        canvas.height = window.innerHeight * dpr;

        const currentFrame = Math.max(1, Math.round(frameIndex.get()));
        drawFrame(currentFrame);
      }
    };

    window.addEventListener("resize", handleResize);
    handleResize();

    return () => window.removeEventListener("resize", handleResize);
  }, []);

  // Completely remove any opacity/fade transitions. 
  // Canvas becomes active and immediately 100% opaque as soon as scroll begins.
  const visibility = useTransform(scrollYProgress, v => v > 0 ? "visible" : "hidden");

  return (
    <motion.div style={{
      position: "fixed",
      top: 0,
      left: 0,
      width: "100%",
      height: "100vh",
      zIndex: -1, /* Over Spline */
      opacity: 1, /* 100% opaque strictly as requested, no fade transitions */
      visibility: visibility as any, /* Only perfectly replace 3D element upon scroll */
      pointerEvents: "none"
    }}>
      <canvas
        ref={canvasRef}
        style={{
          width: "100%",
          height: "100%",
          display: "block",
          objectFit: "cover"
        }}
      />
    </motion.div>
  );
}

"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { motion, useScroll, useMotionValueEvent } from "framer-motion";

export default function Navbar() {
  const { scrollY } = useScroll();
  const [hidden, setHidden] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  useMotionValueEvent(scrollY, "change", (latest) => {
    const previous = scrollY.getPrevious() ?? 0;
    if (latest > previous && latest > 150) {
      setHidden(true);
    } else {
      setHidden(false);
    }
    setIsScrolled(latest > 50);
  });

  return (
    <motion.nav
      variants={{
        visible: { y: 0 },
        hidden: { y: "-100%" },
      }}
      animate={hidden ? "hidden" : "visible"}
      transition={{ duration: 0.35, ease: "easeInOut" }}
      style={{
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        height: "80px",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 5%",
        zIndex: 100,
        background: isScrolled ? "rgba(10, 10, 15, 0.7)" : "transparent",
        backdropFilter: isScrolled ? "blur(20px)" : "none",
        borderBottom: isScrolled ? "1px solid rgba(255,255,255,0.05)" : "1px solid transparent",
        transition: "background 0.3s ease, backdrop-filter 0.3s ease, border 0.3s ease",
      }}
    >
      <Link href="/" style={{ textDecoration: "none" }}>
        <h1 style={{ fontSize: "1.5rem", fontWeight: 700, margin: 0, color: "#fff", letterSpacing: "-0.5px" }}>
          NTI<span style={{ color: "var(--primary)" }}>.</span>
        </h1>
      </Link>

      <div style={{ display: "flex", gap: "2.5rem", alignItems: "center" }}>
        <Link href="#services" className="nav-link">Services</Link>
        <Link href="#work" className="nav-link">Work</Link>
        <Link href="#process" className="nav-link">Process</Link>
      </div>

      <button className="primary-btn" style={{ padding: "0.6rem 1.5rem" }}>
        Get in Touch
      </button>
    </motion.nav>
  );
}

"use client";

import Spline from "@splinetool/react-spline";
import { useState } from "react";
import { motion, useScroll, useTransform } from "framer-motion";

export default function SplineBackground() {
  const [isLoading, setIsLoading] = useState(true);
  const { scrollYProgress } = useScroll();

  // Spline sits permanently at 100% opacity in the background, fully replaced by Canvas dynamically
  const pointerEvents = useTransform(scrollYProgress, [0, 0.05], ["auto", "none"]);

  return (
    <motion.div 
      className="spline-container"
      style={{ pointerEvents: pointerEvents as any }}
    >
      {isLoading && (
        <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%, -50%)", color: "var(--primary)" }}>
          Loading 3D Experience...
        </div>
      )}
      <Spline 
        scene="https://prod.spline.design/05GBhajSH2sAmrNb/scene.splinecode" 
        onLoad={() => setIsLoading(false)}
      />
    </motion.div>
  );
}
